import { cursor } from './cursor';
import { gameStore } from './gameStore';
import { derived } from 'svelte/store';

// keyboardDisabled: 监听 gameStore 状态和 cursor
// 只有固定格子（fixed=true）才禁用输入，用户输入的格子可以反复修改
export const keyboardDisabled = derived(
	[cursor, gameStore],
	([$cursor, $gameStore]) => {
		// 如果没有选中格子，或者游戏暂停，则禁用
		if ($cursor.x === null || $cursor.y === null) return true;
		if ($gameStore.gamePaused) return true;
		
		// 如果是固定格子（题目原有数字），禁用输入
		if ($gameStore.fixed[$cursor.y][$cursor.x]) return true;
		
		return false;
	},
	false,
);